import{_ as t,o as a,c as o,an as r}from"./chunks/framework.BHhYsifu.js";const g=JSON.parse('{"title":"Release process","description":"","frontmatter":{},"headers":[],"relativePath":"developer/release-process.md","filePath":"developer/release-process.md","lastUpdated":null}'),i={name:"developer/release-process.md"};function n(s,e,l,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="release-process" tabindex="-1">Release process <a class="header-anchor" href="#release-process" aria-label="Permalink to &quot;Release process {#release-process}&quot;">â€‹</a></h1><p>ModifiedDistributions.jl follows the Julia ecosystem&#39;s standard release practices, driven by the shared EpiAwarePackageTools workflows. This page describes what those workflows actually do in this repository.</p><h2 id="Release-philosophy" tabindex="-1">Release philosophy <a class="header-anchor" href="#Release-philosophy" aria-label="Permalink to &quot;Release philosophy {#Release-philosophy}&quot;">â€‹</a></h2><ul><li><p><strong>Release frequently</strong>: ideally after every merged pull request to <code>main</code></p></li><li><p><strong>Semantic versioning</strong>: follow <a href="https://semver.org/" target="_blank" rel="noreferrer">SemVer</a> strictly</p></li><li><p><strong>Automated tooling</strong>: registration, tagging, and version increments are workflow-driven</p></li><li><p><strong>SciML ecosystem alignment</strong>: follow established patterns from the broader scientific computing ecosystem</p></li></ul><p><strong>When not to release</strong>:</p><ul><li><p>Work-in-progress features</p></li><li><p>Failing tests</p></li><li><p>Incomplete documentation for new features</p></li></ul><h2 id="Semantic-versioning" tabindex="-1">Semantic versioning <a class="header-anchor" href="#Semantic-versioning" aria-label="Permalink to &quot;Semantic versioning {#Semantic-versioning}&quot;">â€‹</a></h2><p>Following <a href="https://semver.org/" target="_blank" rel="noreferrer">SemVer</a>:</p><ul><li><p><strong>Patch</strong> (<code>1.0.0</code> â†’ <code>1.0.1</code>): Bug fixes, performance improvements</p></li><li><p><strong>Minor</strong> (<code>1.0.1</code> â†’ <code>1.1.0</code>): New features, additions to the API (backwards compatible)</p></li><li><p><strong>Major</strong> (<code>1.1.0</code> â†’ <code>2.0.0</code>): Breaking changes to the public API</p></li></ul><p>Examples:</p><ul><li><p>Adding a new modifier: <strong>Minor</strong></p></li><li><p>Fixing a calculation bug: <strong>Patch</strong></p></li><li><p>Changing a verb&#39;s signature: <strong>Major</strong></p></li><li><p>Adding an optional keyword: <strong>Minor</strong></p></li><li><p>Removing a deprecated function: <strong>Major</strong></p></li></ul><h2 id="Version-management" tabindex="-1">Version management <a class="header-anchor" href="#Version-management" aria-label="Permalink to &quot;Version management {#Version-management}&quot;">â€‹</a></h2><p>Version increments in <code>Project.toml</code> are handled by two workflows rather than by hand.</p><h3 id="Automatic-patch-increment" tabindex="-1">Automatic patch increment <a class="header-anchor" href="#Automatic-patch-increment" aria-label="Permalink to &quot;Automatic patch increment {#Automatic-patch-increment}&quot;">â€‹</a></h3><p><code>.github/workflows/auto-version-increment.yaml</code> runs on every push to <code>main</code>. It compares the version in <code>Project.toml</code> against the previous commit. If the version is unchanged, it opens a pull request that bumps the <strong>patch</strong> version. If the version already changed in the push, it does nothing. This keeps <code>main</code> on an unreleased version after every merge.</p><h3 id="On-demand-increment" tabindex="-1">On-demand increment <a class="header-anchor" href="#On-demand-increment" aria-label="Permalink to &quot;On-demand increment {#On-demand-increment}&quot;">â€‹</a></h3><p><code>.github/workflows/version-on-demand.yaml</code> responds to a <code>/version major|minor|patch</code> comment on a pull request. The comment is gated on the author having <code>write</code>, <code>maintain</code>, or <code>admin</code> permission. On success it commits the chosen increment directly to the pull request branch and reports the old and new versions. Use it when a change needs a minor or major bump rather than the default patch.</p><h2 id="Registration-and-tagging" tabindex="-1">Registration and tagging <a class="header-anchor" href="#Registration-and-tagging" aria-label="Permalink to &quot;Registration and tagging {#Registration-and-tagging}&quot;">â€‹</a></h2><p>Once a version bump is merged to <code>main</code>, registration is triggered from within the repository.</p><h3 id="Triggering-registration" tabindex="-1">Triggering registration <a class="header-anchor" href="#Triggering-registration" aria-label="Permalink to &quot;Triggering registration {#Triggering-registration}&quot;">â€‹</a></h3><p><code>.github/workflows/Register.yml</code> posts the <code>@JuliaRegistrator register</code> comment on <code>main</code>&#39;s HEAD commit for you. There is no need to type that comment by hand. Fire it either way, both gated on the actor having write access:</p><ul><li><p>Comment <code>/register</code> on any issue or pull request</p></li><li><p>Run the workflow manually from <strong>Actions â†’ Register â†’ Run workflow</strong></p></li></ul><p>If the actor lacks write access, the workflow reacts to the comment with a thumbs-down and does nothing else.</p><h3 id="Automated-flow" tabindex="-1">Automated flow <a class="header-anchor" href="#Automated-flow" aria-label="Permalink to &quot;Automated flow {#Automated-flow}&quot;">â€‹</a></h3><ol><li><p><code>Register.yml</code> posts the registration comment on the <code>main</code> commit</p></li><li><p>JuliaRegistrator (the org-installed GitHub App) reacts to the comment and opens a pull request against the Julia General Registry</p></li><li><p>Once the registry pull request merges (usually within about 15 minutes), TagBot creates the GitHub release</p></li><li><p>Documentation is deployed for the new tagged version</p></li></ol><h3 id="TagBot" tabindex="-1">TagBot <a class="header-anchor" href="#TagBot" aria-label="Permalink to &quot;TagBot {#TagBot}&quot;">â€‹</a></h3><p><code>.github/workflows/TagBot.yaml</code> calls the shared EpiAware TagBot workflow. It runs when JuliaTagBot triggers it after registration, or manually via workflow dispatch. It creates the GitHub release with generated changelog and uses the repository&#39;s <code>DOCUMENTER_KEY</code> for authenticated operations.</p><h2 id="Dependency-updates" tabindex="-1">Dependency updates <a class="header-anchor" href="#Dependency-updates" aria-label="Permalink to &quot;Dependency updates {#Dependency-updates}&quot;">â€‹</a></h2><p>Dependency and pinned-reference updates reach this repository through the shared infrastructure rather than a per-repository CompatHelper. Dependabot (<code>.github/dependabot.yml</code>) keeps the pinned reusable-workflow and action references current, and the scheduled template-sync workflow propagates kit-level <code>[compat]</code> and configuration changes. See <a href="/previews/PR45/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a> for details.</p><h2 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">â€‹</a></h2><ul><li><p><strong>GitHub Releases</strong>: created by TagBot for every release, with a generated changelog linking commits and pull requests</p></li><li><p><strong>NEWS.md</strong>: reserved for major releases and significant milestones, giving context for breaking changes and migration guidance</p></li></ul><h2 id="Pre-release-checklist" tabindex="-1">Pre-release checklist <a class="header-anchor" href="#Pre-release-checklist" aria-label="Permalink to &quot;Pre-release checklist {#Pre-release-checklist}&quot;">â€‹</a></h2><p>Before triggering registration:</p><ul><li><p>[ ] All CI tests pass (including pre-commit hooks)</p></li><li><p>[ ] The version number in <code>Project.toml</code> follows semantic versioning</p></li><li><p>[ ] New features have tests and documentation</p></li><li><p>[ ] Examples in docstrings work correctly</p></li></ul><p>For a major release, additionally:</p><ul><li><p>[ ] NEWS.md entry describing the breaking changes and migration path</p></li><li><p>[ ] Deprecation warnings added in a previous release where applicable</p></li><li><p>[ ] Downstream package compatibility assessed</p></li></ul><h2 id="Troubleshooting-releases" tabindex="-1">Troubleshooting releases <a class="header-anchor" href="#Troubleshooting-releases" aria-label="Permalink to &quot;Troubleshooting releases {#Troubleshooting-releases}&quot;">â€‹</a></h2><ul><li><p><strong>Registry pull request fails</strong>: check <code>Project.toml</code> syntax and version conflicts</p></li><li><p><strong>TagBot doesn&#39;t trigger</strong>: verify the <code>DOCUMENTER_KEY</code> secret is configured</p></li><li><p><strong>Registration comment does nothing</strong>: confirm the actor has write access to the repository</p></li></ul><hr><p>This process gives reliable, frequent releases while keeping version management and tagging automated.</p>',40)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
